import re
from typing import Callable, List, Optional

# Validator type: takes field value, returns error message or None
Validator = Callable[[any], Optional[str]]


def required(field_name: str) -> Validator:
    def check(value):
        if not value:
            return f'{field_name} is required'
    return check


def min_length(field_name: str, min_len: int) -> Validator:
    def check(value):
        if isinstance(value, str) and len(value) < min_len:
            return f'{field_name} must be at least {min_len} characters'
    return check


def email_format() -> Validator:
    def check(value):
        if value and not re.match(r'^[\w.+-]+@[\w-]+\.[\w.]+$', value):
            return 'Valid email is required'
    return check


def min_value(field_name: str, minimum: int) -> Validator:
    def check(value):
        if not isinstance(value, int) or value < minimum:
            return f'{field_name} must be at least {minimum}'
    return check


def validate_field(value, validators: List[Validator]) -> List[str]:
    errors = []
    for v in validators:
        err = v(value)
        if err:
            errors.append(err)
    return errors


def validate_user(data: dict) -> list:
    errors = []
    errors.extend(validate_field(data.get('name'), [required('Name'), min_length('Name', 2)]))
    errors.extend(validate_field(data.get('email'), [required('Email'), email_format()]))
    errors.extend(validate_field(data.get('age'), [min_value('Age', 18)]))
    errors.extend(validate_field(data.get('password'), [required('Password'), min_length('Password', 8)]))
    return errors
